@SuppressLint("SetJavaScriptEnabled")
class HybridWebView(context: HybridWebActivity) : WebView(context) {

    val bridge: NativeBridge = NativeBridge(context, this)

    init {
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = true
        settings.databaseEnabled = true
        settings.allowFileAccess = true
        settings.allowContentAccess = true
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        settings.mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
        settings.mediaPlaybackRequiresUserGesture = false
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            settings.safeBrowsingEnabled = true
        }

        addJavascriptInterface(bridge, "NativeBridge")

        webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url ?: return false
                return handleCustomSchemes(context, url)
            }

            override fun shouldOverrideUrlLoading(view: WebView?, url: String?): Boolean {
                if (url == null) return false
                return handleCustomSchemes(context, Uri.parse(url))
            }
        }

        webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.grant(request.resources)
            }
        }
    }

    private fun handleCustomSchemes(context: Context, uri: Uri): Boolean {
        val scheme = uri.scheme ?: return false
        return if (scheme !in listOf("http", "https")) {
            try {
                context.startActivity(Intent(Intent.ACTION_VIEW, uri))
                true
            } catch (_: Exception) {
                true
            }
        } else {
            false
        }
    }
}

class NativeBridge(
    private val activity: HybridWebActivity,
    private val webView: WebView
) {
    private val prefs: SharedPreferences =
        activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)

    @JavascriptInterface
    fun ping(): String {
        return "pong"
    }

    @JavascriptInterface
    fun openCamera(requestId: String?) {
        activity.runOnUiThread {
            activity.requestCamera { success, result ->
                val payload = JSONObject().apply {
                    put("requestId", requestId ?: "")
                    put("success", success)
                    if (success) {
                        put("imageUri", result ?: JSONObject.NULL)
                    } else {
                        put("error", result ?: "Unknown error")
                    }
                }
                emitToWeb("nativeCameraResult", payload.toString())
            }
        }
    }

    @JavascriptInterface
    fun setItem(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getItem(key: String): String {
        return prefs.getString(key, null) ?: ""
    }

    @JavascriptInterface
    fun removeItem(key: String) {
        prefs.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun clearStorage() {
        prefs.edit().clear().apply()
    }

    @JavascriptInterface
    fun requestPushNotifications() {
        activity.runOnUiThread {
            activity.requestPushPermission()
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        return JSONObject().apply {
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("sdkInt", Build.VERSION.SDK_INT)
            put("release", Build.VERSION.RELEASE)
        }.toString()
    }

    fun emitToWeb(eventName: String, jsonPayload: String) {
        val escaped = JSONObject.quote(jsonPayload)
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "window.dispatchEvent(new CustomEvent('$eventName', { detail: JSON.parse($escaped) }));",
                null as ValueCallback<String>?
            )
        }
    }
}